import{_ as a,o as l,c as i,ae as c}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"RPC 어댑터","description":"외부 CLI (signal-cli, 레거시 imsg) 및 게이트웨이 패턴을 위한 RPC 어댑터","frontmatter":{"title":"RPC 어댑터","description":"외부 CLI (signal-cli, 레거시 imsg) 및 게이트웨이 패턴을 위한 RPC 어댑터"},"headers":[],"relativePath":"reference/rpc.md","filePath":"reference/rpc.md","lastUpdated":null}'),o={name:"reference/rpc.md"};function s(t,e,d,n,r,p){return l(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="rpc-어댑터" tabindex="-1">RPC 어댑터 <a class="header-anchor" href="#rpc-어댑터" aria-label="Permalink to &quot;RPC 어댑터&quot;">​</a></h1><p>OpenClaw는 JSON-RPC를 통해 외부 CLI를 통합합니다. 현재 두 가지 패턴이 사용됩니다.</p><h2 id="패턴-a-http-데몬-signal-cli" tabindex="-1">패턴 A: HTTP 데몬 (signal-cli) <a class="header-anchor" href="#패턴-a-http-데몬-signal-cli" aria-label="Permalink to &quot;패턴 A: HTTP 데몬 (signal-cli)&quot;">​</a></h2><ul><li><code>signal-cli</code>는 HTTP를 통한 JSON-RPC로 데몬으로 실행됩니다.</li><li>이벤트 스트림은 SSE(<code>/api/v1/events</code>)입니다.</li><li>상태 프로브: <code>/api/v1/check</code>.</li><li><code>channels.signal.autoStart=true</code>인 경우 OpenClaw가 라이프사이클을 소유합니다.</li></ul><p>설정 및 엔드포인트는 <a href="/openclaw-docs-ko/channels/signal">Signal</a>을 참조하십시오.</p><h2 id="패턴-b-stdio-자식-프로세스-레거시-imsg" tabindex="-1">패턴 B: stdio 자식 프로세스 (레거시: imsg) <a class="header-anchor" href="#패턴-b-stdio-자식-프로세스-레거시-imsg" aria-label="Permalink to &quot;패턴 B: stdio 자식 프로세스 (레거시: imsg)&quot;">​</a></h2><blockquote><p><strong>참고:</strong> 새로운 iMessage 설정에는 대신 <a href="/openclaw-docs-ko/channels/bluebubbles">BlueBubbles</a>를 사용하십시오.</p></blockquote><ul><li>OpenClaw는 <code>imsg rpc</code>를 자식 프로세스로 생성합니다 (레거시 iMessage 통합).</li><li>JSON-RPC는 stdin/stdout을 통해 줄로 구분됩니다 (줄당 JSON 객체 하나).</li><li>TCP 포트 없음, 데몬 불필요.</li></ul><p>사용되는 핵심 메서드:</p><ul><li><code>watch.subscribe</code> → 알림 (<code>method: &quot;message&quot;</code>)</li><li><code>watch.unsubscribe</code></li><li><code>send</code></li><li><code>chats.list</code> (프로브/진단)</li></ul><p>레거시 설정 및 주소 지정 방법(<code>chat_id</code> 권장)은 <a href="/openclaw-docs-ko/channels/imessage">iMessage</a>를 참조하십시오.</p><h2 id="어댑터-가이드라인" tabindex="-1">어댑터 가이드라인 <a class="header-anchor" href="#어댑터-가이드라인" aria-label="Permalink to &quot;어댑터 가이드라인&quot;">​</a></h2><ul><li>게이트웨이가 프로세스를 소유합니다 (시작/중지는 프로바이더 라이프사이클에 연결됨).</li><li>RPC 클라이언트를 견고하게 유지하십시오: 타임아웃, 종료 시 재시작.</li><li>표시 문자열보다 안정적인 ID(예: <code>chat_id</code>)를 선호하십시오.</li></ul>',13)])])}const g=a(o,[["render",s]]);export{u as __pageData,g as default};
